'use client';

import React, { useState, useRef, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useChat } from '../context/ChatContext';
import { useAuth } from '../context/AuthContext';
import './page.css';

export default function ChatPage() {
  const router = useRouter();
  const { activeSession, sendMessage, createSession, setActiveSession, sessions } = useChat();
  const { user } = useAuth();

  const [currentMode, setCurrentMode] = useState('nutri');
  const [isWaiting, setIsWaiting] = useState(false);
  const [inputMode, setInputMode] = useState('text');
  
  const msgInputRef = useRef<HTMLTextAreaElement>(null);
  const chatAreaRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Auto-scroll ke bawah saat ada pesan baru
  useEffect(() => {
    if (chatAreaRef.current) {
      chatAreaRef.current.scrollTop = chatAreaRef.current.scrollHeight;
    }
  }, [activeSession?.messages]);

  const autoResize = (el: HTMLTextAreaElement) => {
    el.style.height = 'auto';
    el.style.height = Math.min(el.scrollHeight, 140) + 'px';
  };

  const fillPrompt = (text: string) => {
    if (msgInputRef.current) {
      msgInputRef.current.value = text;
      autoResize(msgInputRef.current);
      msgInputRef.current.focus();
    }
  };

  const handleSendMessage = async () => {
    if (isWaiting || !msgInputRef.current) return;
    const text = msgInputRef.current.value.trim();
    if (!text) return;

    msgInputRef.current.value = '';
    msgInputRef.current.style.height = 'auto';
    setIsWaiting(true);

    try {
      await sendMessage(text);
    } catch (err) {
      console.error("Error sending message:", err);
    } finally {
      setIsWaiting(false);
    }
  };

  return (
    <div className="app-container">
      {/* SIDEBAR */}
      <aside className="sidebar">
        <div className="logo-wrap">
          <div className="logo-icon">B•G</div>
          <div className="logo-text">BG-AI <span>|</span> NG</div>
        </div>

        <button className="new-chat-btn" onClick={() => createSession()}>
          <span>✦</span> Chat Baru
        </button>

        <div className="mode-tabs">
          <button className={`mode-tab ${currentMode === 'nutri' ? 'active' : ''}`} onClick={() => setCurrentMode('nutri')}>🥦 Gizi</button>
          <button className={`mode-tab ${currentMode === 'vendor' ? 'active' : ''}`} onClick={() => setCurrentMode('vendor')}>🏢 Vendor</button>
          <button className={`mode-tab ${currentMode === 'fraud' ? 'active' : ''}`} onClick={() => setCurrentMode('fraud')}>🔍 Fraud</button>
        </div>

        <div className="history-label">Riwayat Sesi</div>
        <div className="history-list">
          {sessions.map((s) => (
            <div 
              key={s.id} 
              className={`history-item ${activeSession?.id === s.id ? 'active' : ''}`}
              onClick={() => setActiveSession(s.id)}
            >
              <span className="dot"></span>
              <span className="title">{s.title}</span>
            </div>
          ))}
        </div>

        <div className="sidebar-footer">
          <div className="user-profile" onClick={() => router.push('/login')}>
            <div className="user-avatar">{user?.name?.[0].toUpperCase() || 'U'}</div>
            <div className="user-info">
              <div className="user-name">{user?.name || 'User'}</div>
              <div className="user-status">Free Account</div>
            </div>
          </div>
          <div className="footer-links">
            <span onClick={() => router.push('/terms')}>⚖ Ketentuan Layanan</span>
          </div>
        </div>
      </aside>

      {/* MAIN CONTENT */}
      <main className="main-content">
        <header className="main-header">
          <div className="header-title">Sahabat AI Analyzer</div>
          <div className="header-status">● ONLINE</div>
        </header>

        <div className="chat-area" ref={chatAreaRef}>
          {!activeSession || activeSession.messages.length === 0 ? (
            <div className="welcome-screen">
              <div className="welcome-hero">
                <h1>Selamat datang di <span>BG-AI</span></h1>
                <p>Mulai analisis gizi atau verifikasi vendor sekarang.</p>
              </div>
              <div className="suggestion-grid">
                <div className="suggest-card" onClick={() => fillPrompt("Tolong analisis kandungan gizi dari foto ini.")}>
                  <div className="s-icon">📸</div>
                  <div className="s-text">Foto Makanan</div>
                </div>
                <div className="suggest-card" onClick={() => fillPrompt("Apakah menu ini sudah memenuhi standar AKG?")}>
                  <div className="s-icon">🥦</div>
                  <div className="s-text">Standar AKG</div>
                </div>
              </div>
            </div>
          ) : (
            activeSession.messages.map((msg, i) => (
              <div key={i} className={`msg-row ${msg.role}`}>
                <div className="msg-avatar">{msg.role === 'user' ? '👤' : '🌿'}</div>
                <div className="msg-bubble">
                  {msg.text}
                </div>
              </div>
            ))
          )}
          {isWaiting && <div className="msg-row assistant"><div className="msg-bubble typing">Mengetik...</div></div>}
        </div>

        {/* INPUT BAR */}
        <div className="input-section">
          <div className="input-modes">
            <button className={inputMode === 'text' ? 'active' : ''} onClick={() => setInputMode('text')}>✏ Teks</button>
            <button className={inputMode === 'image' ? 'active' : ''} onClick={() => setInputMode('image')}>📸 Foto</button>
          </div>
          <div className="input-container">
            <textarea 
              ref={msgInputRef}
              placeholder="Tanya Sahabat AI..." 
              onInput={(e) => autoResize(e.currentTarget)}
              onKeyDown={(e) => e.key === 'Enter' && !e.shiftKey && (e.preventDefault(), handleSendMessage())}
            />
            <button className="action-btn" onClick={() => fileInputRef.current?.click()}>📎</button>
            <button className="send-btn" onClick={handleSendMessage} disabled={isWaiting}>➤</button>
          </div>
          <input type="file" ref={fileInputRef} hidden />
        </div>
      </main>

      {/* RIGHT PANEL (KOSONG sesuai permintaan) */}
      <aside className="right-panel">
        <div className="rp-section-title">Status Sistem</div>
        <div className="rp-section-title">Model Aktif</div>
        <div className="rp-section-title">Sesi Ini</div>
      </aside>
    </div>
  );
}